// // This module is designed to capture a 3-bit input value (DIN) on the falling edge of the clock signal (CLK) and hold this value as the output (DOUT).
module top_module(CLK,DIN,DOUT);input CLK;
input  [2:0] DIN;
output [2:0] DOUT;
reg [2:0] DOUT;

always @(posedge CLK)
      DOUT <= DIN;

endmodule
